import React, { useState } from 'react';
import './EditPurchase.css';

const EditPurchase = ({ purchase, handleUpdate }) => {
    const [updatedPurchase, setUpdatedPurchase] = useState({ ...purchase });
  
    const handleChange = (e) => {
      const { name, value } = e.target;
      setUpdatedPurchase((prevPurchase) => ({
        ...prevPurchase,
        [name]: value,
      }));
    };
  
    const handleSubmit = (e) => {
      e.preventDefault();
      handleUpdate(updatedPurchase);
    };
  
    return (
      <form onSubmit={handleSubmit} className="edit-purchase-form">
      <label htmlFor="editLocation">Location:</label>
      <input
        type="text"
        id="editLocation"
        name="location"
        value={updatedPurchase.location}
        onChange={handleChange}
        required
      />

      <label htmlFor="editMaterialID">Material ID:</label>
      <input
        type="text"
        id="editMaterialID"
        name="materialid"
        value={updatedPurchase.materialid}
        onChange={handleChange}
        required
      />

      <label htmlFor="editQuantity">Quantity:</label>
      <input
        type="number"
        id="editQuantity"
        name="quantity"
        value={updatedPurchase.quantity}
        onChange={handleChange}
        required
      />

      
    <button type="submit" className="edit-purchase-btn">Update</button>
    </form>
  );
};

export default EditPurchase;
